name: Preprod Deployment

on:
  workflow_dispatch: 
  pull_request:
    types: 
      - closed
    branches:
      - pre-prod
env:
  AWS_REGION: ap-south-1
  ECR_REPOSITORY: ramfincorp/loan-backend
  BASE_PATH: /home/ubuntu/preprod/onboarding_service
  SERVICE_NAME: loan-backend
  GIT_BRANCH: pre-prod

jobs:
  build:
    if: github.event.pull_request.merged == true
    runs-on: [self-hosted, ramfin]
    outputs:
      image_tag: ${{ steps.set_tag.outputs.image_tag }}

    steps:
      - name: Set image tag
        id: set_tag
        run: echo "image_tag=1.${{ github.run_number }}" >> $GITHUB_OUTPUT

      - name: Configure AWS credentials
        uses: aws-actions/configure-aws-credentials@v2
        with:
          aws-region: ${{ env.AWS_REGION }}
          role-to-assume: ${{ secrets.AWS_ROLE_ARN }}

      - name: Login to Amazon ECR
        shell: bash
        run: |
          aws ecr get-login-password --region ${{ env.AWS_REGION }} \
          | docker login --username AWS --password-stdin 361795871686.dkr.ecr.${{ env.AWS_REGION }}.amazonaws.com

      - name: Checkout code
        run: |
          cd ${{ env.BASE_PATH }}
          git checkout ${{ env.GIT_BRANCH }}
          git reset --hard origin/${{ env.GIT_BRANCH }}
          git pull origin ${{ env.GIT_BRANCH }}


      - name: Build and Push Docker image
        shell: bash
        run: |
          cd ${{ env.BASE_PATH }}
          IMAGE_NAME=361795871686.dkr.ecr.${{ env.AWS_REGION }}.amazonaws.com/${{ env.ECR_REPOSITORY }}:${{ steps.set_tag.outputs.image_tag }}

          echo "Building Image: ${IMAGE_NAME}"
          docker build \
          -t "${IMAGE_NAME}" \
          --platform linux/amd64 \
          -f Dockerfile .

          echo "Pushing image: ${IMAGE_NAME}"
          docker push "${IMAGE_NAME}"

  deploy:
    needs: build
    name: Deploy
    if: github.event.pull_request.merged == true
    runs-on: [self-hosted, ramfin]
    steps:
      - name: Checkout code
        run: |
          cd ${{ env.BASE_PATH }}
          git checkout ${{ env.GIT_BRANCH }}
          git pull origin ${{ env.GIT_BRANCH }}

      - name: Verify Kubernetes Context
        run: |
          kubectl config use-context arn:aws:eks:ap-south-1:361795871686:cluster/pre-prod-eks-cluster
          if ! kubectl cluster-info > /dev/null 2>&1; then
            echo "Error: Could not connect to the Kubernetes cluster context."
            exit 1
          fi

      - name: Deploy using deploy.sh
        run: |
          cd ${{ env.BASE_PATH }}/cicd
          chmod +x deploy.sh
          ./deploy.sh ${{ env.SERVICE_NAME }} ${{ needs.build.outputs.image_tag }}







apiVersion: apps/v1
kind: Deployment
metadata:
  name: {{ .Values.name }}
  namespace: {{ .Values.name }}
spec:
  replicas: {{ .Values.replicaCount }}
  selector:
    matchLabels:
      app: {{ .Values.name }}
  template:
    metadata:
      labels:
        app: {{ .Values.name }}
    spec:
      containers:
        - name: {{ .Values.name }}
          image: {{ .Values.image.repository }}:{{ .Values.image.tag }}
          imagePullPolicy: Always
          ports:
            - containerPort: {{ .Values.service.port }}
          volumeMounts:
            - name: env-secret
              mountPath: /app/.env
              subPath: .env
          env:
            - name: NODE_ENV
              value: "production"
          resources:
{{- toYaml .Values.resources | nindent 12 }}
      volumes:
        - name: env-secret
          secret:
            secretName: {{ .Values.envSecretName | default (printf "%s-env" .Values.name) }}



apiVersion: autoscaling/v2
kind: HorizontalPodAutoscaler
metadata:
  name: {{ .Values.name }}-hpa
  namespace: {{ .Values.name }}
spec:
  scaleTargetRef:
    apiVersion: apps/v1
    kind: Deployment
    name: {{ .Values.name }}
  minReplicas: {{ .Values.replicaCount }}
  maxReplicas: 5
  metrics:
    - type: Resource
      resource:
        name: cpu
        target:
          type: Utilization
          averageUtilization: 70
    - type: Resource
      resource:
        name: memory
        target:
          type: Utilization
          averageUtilization: 80



apiVersion: gateway.networking.k8s.io/v1
kind: HTTPRoute
metadata:
  name: {{ .Values.name }}-route
  namespace: {{ .Values.name }}
  labels:
    app: {{ .Values.name }}
spec:
  parentRefs:
  - name: {{ .Values.gateway.name }}
    namespace: {{ .Values.gateway.namespace | default .Values.name }}
  hostnames:
  {{- range .Values.gateway.hosts }}
  - {{ . | quote }}
  {{- end }}
  rules:
  - matches:
    - path:
        type: PathPrefix
        value: /
    backendRefs:
    - name: {{ .Values.service.name }}
      port: {{ .Values.service.port }}







apiVersion: v1
kind: Service
metadata:
  name: {{ .Values.service.name }}
  namespace: {{ .Values.name }}
  labels:
    app: {{ .Values.name }}
    app.kubernetes.io/managed-by: "Helm"
  annotations:
    meta.helm.sh/release-name: {{ .Values.name }}
    meta.helm.sh/release-namespace: {{ .Values.name }}
spec:
  selector:
    app: {{ .Values.name }}
  ports:
    - protocol: TCP
      port: 80
      targetPort: {{ .Values.service.port }}
  type: {{ .Values.service.type }}



apiVersion: v2
name: loan-backend
version: 0.1.0
description: A Helm chart for deploying the crm-backend service
appVersion: "1.0"
keywords:
  - backend
  - loan
  - kubernetes
maintainers:
  - name: Ramfincorp



replicaCount: 1

name: loan-backend
image:
  repository: 361795871686.dkr.ecr.ap-south-1.amazonaws.com/ramfincorp/loan-backend
  tag: "1.0"
  pullPolicy: IfNotPresent

service:
  name: loan-backend-svc
  type: ClusterIP
  port: 8080

envSecretName: "loan-backend-env"

gateway:
  name: "envoy-gateway"
  namespace: "envoy-system"
  hosts:
    - "loan-backend.preprod.ramfincorp.com"

probe:
  liveness:
    endpoint: "/health"
    initialDelaySeconds: 120
    periodSeconds: 30

resources:
  requests:
    memory: "2Gi"
    cpu: "1"
  limits:
    memory: "2Gi"
    cpu: "1"







#!/usr/bin/env bash

serviceName="${1}"
imageTag="${2}"
if [ -z "${serviceName}" ] || [ -z "${imageTag}" ]; then
  echo "Usage: $0  "
  exit 1
fi
namespace="${serviceName}"

echo "Deploying ${serviceName} with image tag ${imageTag} in namespace: ${namespace}"

echo "Creating/Updating secret ${serviceName}-env from ../.env in namespace: ${namespace}"
kubectl create namespace "${namespace}" --dry-run=client -o yaml | kubectl apply -f -
kubectl create secret generic "${serviceName}-env" \
  --from-file=.env=/home/ubuntu/preprod/env/loan-backend-preprod-env \
  --namespace "${namespace}" \
  --dry-run=client -o yaml | kubectl apply -f -

helm upgrade --install \
  "${serviceName}" "./helm" \
  --set image.tag="${imageTag}" \
  --namespace "${namespace}" \
  --create-namespace \
  -f ./helm/values.yaml



