interface Reader {
  find(item: Partial): Promise
  findOne(id: string | Partial): Promise
  exist(id: string | Partial): Promise
}
⋮----
find(item: Partial): Promise
findOne(id: string | Partial): Promise
exist(id: string | Partial): Promise
⋮----
type BaseRepository = Writer & Reader
⋮----
export abstract class KnexRepository implements BaseRepository
