// GetSummary Response
// 1. Success Auto Approved
interface IHypervergeGetSummaryResultResponseAutoApproved {
  status: 'success';
  statusCode: number;
  metadata: {
    requestId: string;
  };
  result: {
    flags: {
      source: string;
      subSource?: string;
      values: Record;
    }[];
    userDetails: {
      Selfie_Validation_imageUrl: string;
    };
    status: 'auto_approved';
    transactionId: string;
    failureReason: {
      text: string;
      id: string;
    };
  };
}
⋮----
// 2. Success Auto Declined
interface IHypervergeGetSummaryResultResponseAutoDeclined {
  status: 'success';
  statusCode: number;
  metadata: {
    requestId: string;
  };
  result: {
    flags: {
      source: string;
      subSource?: string;
      values: Record;
    }[];
    userDetails: {
      Selfie_Validation_imageUrl?: string;
    };
    status: 'auto_declined';
    transactionId: string;
    reviewDetails: {
      reviewer: string;
    };
  };
}
⋮----
// 3. Success User Cancelled
interface IHypervergeGetSummaryResultResponseUserCancelled {
  status: 'success';
  statusCode: number;
  metadata: {
    requestId: string;
  };
  result: {
    flags: {
      source: string;
      subSource?: string;
      values: Record;
    }[];
    userDetails: {
      Selfie_Validation_imageUrl?: string;
    };
    status: 'user_cancelled';
    transactionId: string;
    reviewDetails: {
      reviewer: string;
    };
    debugInfo: {
      latestModule: string;
    };
  };
}
⋮----
// TransactionId Not Found
export interface IHypervergeGetSummaryResultResponseTransactionNotFound {
  status: 'failure';
  statusCode: 400;
  metadata: {
    requestId: string;
  };
  result: {
    error: 'TransactionId not found';
  };
}
⋮----
// Authentication Error
export interface IHypervergeGetSummaryResultResponseAuthError {
  status: 'failure';
  statusCode: 401;
  metadata: {
    requestId: string;
  };
  result: {
    error: 'Missing/Invalid credentials';
  };
}
⋮----
// 5xx Internal Server Error
export interface IHypervergeGetSummaryResultResponseServerError {
  status: 'failure';
  statusCode: 500;
  metadata: {
    requestId: string;
  };
  result: {
    error: 'Internal Server Error';
  };
}
⋮----
export type IHypervergeGetSummaryResultResponse =
  // Success cases
  | IHypervergeGetSummaryResultResponseAutoApproved
  | IHypervergeGetSummaryResultResponseAutoDeclined
  | IHypervergeGetSummaryResultResponseUserCancelled;
