#!/bin/sh
# wait-for.sh - Wait for services to be ready before starting the application

set -e

host="$1"
port="$2"
service_type="$3"
shift 3
cmd="$@"

# Default timeout (in seconds)
timeout=30
elapsed=0
interval=1

echo "Waiting for $service_type ($host:$port) to be ready..."

case "$service_type" in
  mysql)
    until [ "$elapsed" -ge "$timeout" ] || nc -z "$host" "$port"; do
      elapsed=$(( elapsed + interval ))
      echo "Waiting for MySQL at $host:$port... ${elapsed}s"
      sleep $interval

      if [ "$elapsed" -ge "$timeout" ]; then
        echo "Timeout reached while waiting for MySQL to be ready!"
        exit 1
      fi
    done
    ;;

  mongodb)
    until [ "$elapsed" -ge "$timeout" ] || mongosh --host "$host" --port "$port" --eval "db.runCommand('ping').ok" >/dev/null 2>&1; do
      elapsed=$(( elapsed + interval ))
      echo "Waiting for MongoDB at $host:$port... ${elapsed}s"
      sleep $interval

      if [ "$elapsed" -ge "$timeout" ]; then
        echo "Timeout reached while waiting for MongoDB to be ready!"
        exit 1
      fi
    done
    ;;

  *)
    echo "Unknown service type: $service_type. Supported types: mysql, mongodb"
    exit 1
    ;;
esac

echo "$service_type is up and running!"

# Execute the command if provided
if [ -n "$cmd" ]; then
  echo "Executing command: $cmd"
  exec $cmd
fi
